package abiFfVault

import (
	"math/big"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"github.com/tonkeeper/tongo/boc"
	"github.com/tonkeeper/tongo/tlb"
)

func TestVaultStorage_UnmarshalTLB(t *testing.T) {
	cell := boc.MustDeserializeSinglRootHex("")
	var storage VaultStorage
	require.NoError(t, storage.UnmarshalTLB(cell, tlb.NewDecoder()))

	assert.Equal(t, tlb.Coins(169820), storage.AssetStaked)

	expectedDistributedStables, _ := new(big.Int).SetString("227050174430635989259679729521900975809", 10)
	assert.Equal(t, 0, (*big.Int)(&storage.DistributedStables).Cmp(expectedDistributedStables))

	assert.Equal(t, tlb.Uint32(100), storage.MaxPriceChange)
	assert.Equal(t, tlb.Uint64(6), storage.NextItemIndex)
	assert.Equal(t, "0:23beaa1c6615ef66b1ae810040411c0a87e81e4322738de42f45d3117d19fbbf", storage.Admin.String())
	assert.Equal(t, tlb.Coins(169820), storage.AssetAmountOnVault)
	assert.Equal(t, tlb.Coins(100000), storage.StableAmountOnVault)

	sd := storage.StaticData.Value
	assert.Equal(t, "0:3934fca37d9ced0e6f237130704c053d346b20244930d7dcfad7279c5f44e5b1", sd.PYTHOracle.String())
	assert.Equal(t, "0:cb9edd90eee09419360a7cf2ba3a82e9f158dc08caf30ab0a41a93fa2f64c8cb", sd.AssetJettonWallet.String())
	assert.Equal(t, "0:1ff33f3ead02eef329ae133392dc62a0a6d9e332c55e7ebc403e94800fe72f1a", sd.StableJettonWallet.String())
	assert.Equal(t, tlb.Uint8(6), sd.StableDecimals)
	assert.Equal(t, tlb.Uint8(6), sd.AssetDecimals)
}
